		}
	)

	if _, err := s.builder.Insert("flags").
		Columns("namespace_key", "\"key\"", "\"type\"", "name", "description", "enabled", "created_at", "updated_at").
		Values(
			flag.NamespaceKey,
			flag.Key,
			flag.Type,
			flag.Name,
			flag.Description,
			flag.Enabled,
			&fliptsql.Timestamp{Timestamp: flag.CreatedAt},
